        typeBuilder.HasIndex(channelStatistic => channelStatistic.Id);
        
        //  Настройка свойства "Количество значений".
        typeBuilder.Property(channelStatistic => channelStatistic.Count);
        typeBuilder.HasIndex(channelStatistic => channelStatistic.Count);
        
        //  Настройка свойства "Минимальное значение".
