        typeBuilder.HasIndex(channelStatistic => channelStatistic.Max);
        
        //  Настройка свойства "Среднее значение".
        typeBuilder.Property(channelStatistic => channelStatistic.Average);
        typeBuilder.HasIndex(channelStatistic => channelStatistic.Average);
        
        //  Настройка свойства "Среднеквадратическое отклонение".
        typeBuilder.Property(channelStatistic => channelStatistic.Deviation);
        typeBuilder.HasIndex(channelStatistic => channelStatistic.Deviation);
        
        //  Настройка свойства "Сумма значений".
